import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Chaos (混沌)","description":"","frontmatter":{},"headers":[],"relativePath":"en/realms/chaos.md","filePath":"en/realms/chaos.md","lastUpdated":1775394001000}'),s={name:"en/realms/chaos.md"};function n(o,t,i,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="chaos-混沌" tabindex="-1">Chaos (混沌) <a class="header-anchor" href="#chaos-混沌" aria-label="Permalink to &quot;Chaos (混沌)&quot;">​</a></h1><p><span class="realm-badge realm-chaos">Chaos</span> is the realm of primordial disorder. Chaos Awakeners specialize in flexibility, mixing cards from multiple realms, and accelerating Silver Key generation.</p><h2 id="core-identity" tabindex="-1">Core Identity <a class="header-anchor" href="#core-identity" aria-label="Permalink to &quot;Core Identity&quot;">​</a></h2><p>Chaos is the most versatile realm. Unlike other realms that reward mono-realm deckbuilding, Chaos actively encourages hybrid compositions. Chaos Awakeners and cards can be slotted into any team without penalty.</p><h2 id="key-mechanics" tabindex="-1">Key Mechanics <a class="header-anchor" href="#key-mechanics" aria-label="Permalink to &quot;Key Mechanics&quot;">​</a></h2><h3 id="cross-realm-mixing" tabindex="-1">Cross-Realm Mixing <a class="header-anchor" href="#cross-realm-mixing" aria-label="Permalink to &quot;Cross-Realm Mixing&quot;">​</a></h3><p>Chaos cards and Awakeners do not disrupt other realm synergies. This means:</p><ul><li>A Chaos Awakener can join an Aequor team without weakening Aequor synergy.</li><li>Chaos cards from Investigation or other sources can supplement any realm deck.</li><li>Chaos teams themselves can cherry-pick the strongest cards from all realms.</li></ul><h3 id="realm-talent-death-resist" tabindex="-1">Realm Talent: Death Resist <a class="header-anchor" href="#realm-talent-death-resist" aria-label="Permalink to &quot;Realm Talent: Death Resist&quot;">​</a></h3><p>If any Chaos Awakener is in the team, the party gains an additional <strong>100% Death Resist</strong> (one free death prevention).</p><h3 id="pure-chaos-resonance-silver-key-resonance" tabindex="-1">Pure Chaos Resonance: Silver Key Resonance <a class="header-anchor" href="#pure-chaos-resonance-silver-key-resonance" aria-label="Permalink to &quot;Pure Chaos Resonance: Silver Key Resonance&quot;">​</a></h3><p>In a pure Chaos composition, the team auto-generates <strong>250 Silver Key Energy per turn</strong>. Key Orders can be used <strong>twice per turn</strong> -- the second use allows selecting from any other unlocked Key Order.</p><h3 id="co-resonance-with-other-realms-v2-0" tabindex="-1">Co-Resonance with Other Realms (v2.0+) <a class="header-anchor" href="#co-resonance-with-other-realms-v2-0" aria-label="Permalink to &quot;Co-Resonance with Other Realms (v2.0+)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Partner Realm</th><th>Effect</th></tr></thead><tbody><tr><td><span class="realm-badge realm-aequor">Aequor</span></td><td>After a Chaos Awakener uses Aliemus Burst, 1 extra tentacle attacks the enemy at end of turn; all Aequor Awakeners gain 10 Aliemus.</td></tr><tr><td><span class="realm-badge realm-caro">Caro</span></td><td>Each Chaos Awakener stores 2% max HP into Scarlet Furnace at end of turn; Chaos Aliemus Burst grants +25% Embryo Fusion.</td></tr><tr><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Each Chaos Awakener permanently increases max HP by 1% at battle start, reduces all enemy max HP by 0.5%, and grants all Ultra Awakeners +10% Crit DMG.</td></tr></tbody></table><h3 id="silver-key-acceleration" tabindex="-1">Silver Key Acceleration <a class="header-anchor" href="#silver-key-acceleration" aria-label="Permalink to &quot;Silver Key Acceleration&quot;">​</a></h3><p>Chaos cards frequently generate bonus Silver Key energy. In a Chaos-focused team, you can reach the 1000 Silver Key threshold significantly faster, activating your <a href="./../key-orders/">Key Order</a> earlier in the fight.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Chaos teams excel when you have a powerful Key Order equipped. The faster Silver Key generation is wasted if your Key Order is weak. Invest in your Key Order alongside your Chaos Awakeners. The most obvious advantage is Death Resist -- once you understand how to sell Death Resist strategically, you have mastered the basics of Chaos.</p></div><h2 id="chaos-awakeners" tabindex="-1">Chaos Awakeners <a class="header-anchor" href="#chaos-awakeners" aria-label="Permalink to &quot;Chaos Awakeners&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Awakener</th><th>Role</th><th>Tier</th><th>Availability</th></tr></thead><tbody><tr><td>24</td><td>Attack</td><td>T0</td><td>Limited</td></tr><tr><td>Alva</td><td>Defense</td><td>T0</td><td>Standard</td></tr><tr><td>Danmo</td><td>Attack</td><td>T1</td><td>Limited</td></tr><tr><td>Doll</td><td>Attack</td><td>T0</td><td>Standard</td></tr><tr><td>Doll: Inferno</td><td>Support</td><td>—</td><td>Limited</td></tr><tr><td>Galen</td><td>Sub-Attack</td><td>T3</td><td>Standard</td></tr><tr><td>Hameln</td><td>Support</td><td>—</td><td>Standard</td></tr><tr><td>Karen</td><td>Support</td><td>—</td><td>Standard</td></tr><tr><td>Kathigu-Ra</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Lily</td><td>Defense</td><td>T1</td><td>Standard</td></tr><tr><td>Lotan</td><td>Defense</td><td>T1</td><td>Standard</td></tr><tr><td>Mouchette</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Nodera</td><td>Attack</td><td>T2</td><td>Standard</td></tr><tr><td>Nymphia</td><td>Support</td><td>T3</td><td>Standard</td></tr><tr><td>Ogier</td><td>Support</td><td>T1</td><td>Standard</td></tr><tr><td>Pandya</td><td>Sub-Attack</td><td>T2</td><td>Standard</td></tr><tr><td>Ramona</td><td>Support</td><td>T1</td><td>Standard</td></tr><tr><td>Ramona: Timeworn</td><td>Attack</td><td>T0</td><td>Limited</td></tr><tr><td>Tawil</td><td>Support</td><td>—</td><td>Standard</td></tr></tbody></table><h2 id="team-building-with-chaos" tabindex="-1">Team Building with Chaos <a class="header-anchor" href="#team-building-with-chaos" aria-label="Permalink to &quot;Team Building with Chaos&quot;">​</a></h2><ul><li><strong>Pure Chaos</strong> -- All Chaos Awakeners for maximum Silver Key generation and Key Order uptime (use Key Orders 2x per turn).</li><li><strong>Chaos Support</strong> -- 1-2 Chaos Awakeners slotted into another realm team to provide Death Resist and co-resonance bonuses without breaking synergy.</li><li><strong>#24 National Team</strong> -- 24 + Ramona + Ogier + Lily: The go-to pure Chaos team. 24 alone carries the damage.</li><li><strong>Roster Filler</strong> -- Use Chaos Awakeners to fill gaps when you lack enough Awakeners for a mono-realm team.</li></ul><h2 id="strengths-and-weaknesses" tabindex="-1">Strengths and Weaknesses <a class="header-anchor" href="#strengths-and-weaknesses" aria-label="Permalink to &quot;Strengths and Weaknesses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strengths</th><th>Weaknesses</th></tr></thead><tbody><tr><td>Maximum flexibility</td><td>No unique damage mechanic (no Tentacles, Embryos, or extra turns)</td></tr><tr><td>Fast Silver Key generation</td><td>Relies heavily on Key Order quality</td></tr><tr><td>Death Resist safety net</td><td>Raw damage potential lower than focused realm teams</td></tr><tr><td>Works with any team</td><td>Lacks deep roster compared to other realms</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Realms Overview</a></li><li><a href="./../key-orders/">Key Orders</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',25)])])}const y=e(s,[["render",n]]);export{u as __pageData,y as default};
